INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Expansion into PG Courses', '', 'The institution later expanded into postgraduate education including MA, MSc, and MCom programs.', 'Postgraduate Education', '');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Strong Sports Performance', '', 'Students from the college regularly participate in district and university-level sports competitions including cricket, football, volleyball, kabaddi, and athletics.', 'Sports', '');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Active NCC and NSS Programs', '', 'The college actively conducts NCC and NSS activities including social service, leadership camps, and awareness programs.', 'NCC/NSS', '');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Center of Excellence / Model College', '', 'Recognized by the Rajasthan Government as a Model College and Center of Excellence for higher education.', 'Education', '');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Early Introduction of Commerce Stream', '', 'The college introduced Commerce education in 1949, becoming one of the early institutions in the region to offer commerce studies.', 'Commerce Education', '1949');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Large Campus and Advanced Facilities', '', 'The college has a large campus with science laboratories, library, sports grounds, classrooms, and hostel facilities.', 'Infrastructure', '');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Prime Location Near Railway Station', '', 'The college is located near Churu Railway Station, making transportation convenient for students from nearby regions.', 'Location', '');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('NAAC Accredited Institution', '', 'The college has received NAAC accreditation and actively operates IQAC for quality improvement in education.', 'Accreditation', '');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Historic Government College Since 1945', '', 'Government Lohia College Churu is one of the oldest and most prestigious government colleges in Rajasthan, established in 1945.', 'College Achievement', '1945');
INSERT INTO public.achievements (title, student_name, description, category, year) VALUES ('Leading Government College of Churu Region', '', 'Government Lohia College is considered one of the most well-known government colleges in Churu for Arts, Commerce, and Science education.', 'Academics', '');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('What are the college canteen timings and popular items?', 'The Lohia College canteen is open from 9:30 AM to 3:30 PM on all working days. Popular items include hot Samosas (Rs. 10), Chai (Rs. 5), Bread Pakora (Rs. 12).', 'Canteen');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('What is the procedure to issue books from the college library?', 'Present a valid Library Card. Issue up to 2 books for 14 days. Late fee of Rs. 1 per day.', 'Library');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('Are there parking fees or rules for student vehicles on campus?', 'Student parking is near the main gate. Bicycle parking is free. Two-wheelers need valid college ID passes. No fees for regular students.', 'Parking & Campus');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('What are the college canteen timings and popular items?', 'The Lohia College canteen is open from 9:30 AM to 3:30 PM on all working days. Popular items include hot Samosas (Rs. 10), Chai (Rs. 5), Bread Pakora (Rs. 12).', 'Canteen');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('How can a student join the NSS unit of Lohia College?', 'Lohia College has active NSS units. Applications for registration in NSS start in July/August every year. Students can contact the NSS Program Officers in their respective departments to get the application form. Selection is done on a merit and interview basis.', 'NSS & NCC');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('Are there parking fees or rules for student vehicles on campus?', 'Student parking is near the main gate. Bicycle parking is free. Two-wheelers need valid college ID passes. No fees for regular students.', 'Parking & Campus');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('Are there parking fees or rules for student vehicles on campus?', 'Student parking is located near the main entrance gate. Bicycle parking is free of charge. Two-wheelers (motorcycles/scooters) must have valid college ID passes to enter. No parking fees are charged to regular college students with proper ID.', 'Parking & Campus');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('What is the procedure to issue books from the college library?', 'To issue books, students must present a valid Library Card which is made in the beginning of the semester. A student can issue up to 2 books at a time for a duration of 14 days. A late fee of Rs. 1 per day is charged for overdue books.', 'Library');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('What is the procedure to issue books from the college library?', 'Present a valid Library Card. Issue up to 2 books for 14 days. Late fee of Rs. 1 per day.', 'Library');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('What are the college canteen timings and popular items?', 'The Lohia College canteen is open from 9:30 AM to 3:30 PM on all working days (Monday to Friday). Popular items include hot Samosas (Rs. 10 each), Chai (Rs. 5), Bread Pakora (Rs. 12), and cold beverages.', 'Canteen');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('How can a student join the NSS unit of Lohia College?', 'Applications start in July/August. Contact NSS Program Officers in your department. Selection is merit and interview based.', 'NSS & NCC');
INSERT INTO public.college_faqs (question, answer, category) VALUES ('How can a student join the NSS unit of Lohia College?', 'Applications start in July/August. Contact NSS Program Officers in your department. Selection is merit and interview based.', 'NSS & NCC');
