INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'history', 'College History Summary', 'Established in 1945 at intermediate level with 47 students. Shifted to the present location in 1949 and upgraded to graduation level in Commerce. Seth K.L. Lohia built the original huge building, and more additions have been made over time. It was declared a Model College by the Govt of Rajasthan in 2006.') ON CONFLICT (search_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'library', 'College Library & Reading Room', 'The library is rich with over 100,184 books. It includes a UGC section (28,932 books), SC/ST section (4,463 books), General section (62,161 books), and RUSA section (4,628 books). It subscribes to 43 journals and magazines, and several newspapers (Dainik Bhaskar, Rajasthan Patrika, etc.). Students have free access to open shelves.') ON CONFLICT (search_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'founder', 'Founder: Seth Kanhiya Lal Lohia (1884-1957)', 'Seth Kanhiya Lal Lohia was an eminent entrepreneur doing a brisk jute business in Calcutta. He dreamed of building a college in his home town for a holy cause during the pre-independence era. He is a visionary who brought this desert town on the educational map. Churu came to be known by Lohia College because of its excellent infrastructure and standards. This uneducated businessman had incredible foresight, providing higher education opportunities when facilities were far away.') ON CONFLICT (search_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'exam_general', '1. MGSU Examination Overview', 'Maharaja Ganga Singh University (MGSU) follows both Semester and Annual systems.
INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'exam_cbc_grading', '5. CBCS Grading (SGPA/CGPA)', 'MGSU uses a letter grade system:
INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'hostel', 'Hostel Facility', 'The hostel is situated on the college campus itself, just a stone''s throw from the main college building. It is among the largest (perhaps the largest one) in Rajasthan with 128 rooms, one auditorium, and playgrounds. This is to say something about the farsightedness of that great visionary, Seth Kanhaiya Lal Lohia, that he built such a big hostel at a time when there was absolutely no need of such a big size. The fee structure is very reasonable and even poor students can afford it.') ON CONFLICT (search_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'vision', 'College Vision', 'To become a center of academic excellence by providing quality education, practical training, and research opportunities that shape responsible and capable citizens for the future.') ON CONFLICT (search_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'mission', 'College Mission', '1. To provide inspired learning and construct value based education system.\n2. To ensure exposure to diverse disciplines.\n3. To encourage merit and enhance employability skills.\n4. To instil a culture of hands-on learning and research.\n5. To impart quality education at an affordable price.\n6. To make available quality education to disadvantageous, marginalized and differently able students.\n7. To lay stress on holistic development of the students’ personality by ensuring their participation in co-curricular and extra-curricular activities.\n8. To inculcate scientific temperament and make them technology-savvy and eco-friendly.') ON CONFLICT (search_key) DO UPDATE SET content = EXCLUDED.content;
