INSERT INTO public.college_knowledge (category, search_key, title, content) VALUES ('General Info', 'exam_practical', '3. Practical Examination System (Science & Arts)', 'Practical exams are mandatory for Science (Physics, Chemistry, Bio), Geography, and Psychology.
